"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   mockStories: () => (/* binding */ mockStories)\n/* harmony export */ });\nconst mockStories = [\n    {\n        id: \"1\",\n        title: \"Through the Valley — How I Found Peace After Loss\",\n        content: `The phone call came at 3:14 AM on a Tuesday. I remember the exact time because I had been lying awake, somehow sensing that something was about to change. My mother had passed. The woman who sang hymns while cooking, who pressed scripture verses into my palm when I was afraid, who called me her \"prayer warrior\" — she was gone.\\n\\nFor months I walked through a fog so thick I could barely breathe. My faith, which had always felt like solid ground beneath my feet, suddenly seemed like sand. I cried out to God in the middle of the night. I asked why. I bargained. I was angry.\\n\\nBut one morning, about six months after her passing, I sat in her favorite chair — the one by the east window where she used to watch the sunrise — and the light came in differently. It was golden and warm and it filled the whole room. And I heard her voice, not audibly, but in my spirit: \"I'm okay, baby. More than okay. Keep standing.\"\\n\\nSomething broke open in me that morning. Not broke apart — broke open. Like a seed cracking so something beautiful can grow. I began to see that grief and faith are not opposites. They're companions on the same road. And that road leads somewhere good.\\n\\nToday I run a grief support group at my local church. I tell every person who walks through the door what my mother taught me: the valley is not the destination. You're just passing through. Keep walking. Keep standing.`,\n        excerpt: \"The phone call came at 3:14 AM on a Tuesday. I remember the exact time because I had been lying awake, somehow sensing that something was about to change…\",\n        author_name: \"Evelyn M.\",\n        category: \"Loss & Grief\",\n        image_url: null,\n        likes: 142,\n        prayers: 89,\n        encouragements: 57,\n        created_at: \"2024-11-15T09:22:00Z\",\n        is_featured: true\n    },\n    {\n        id: \"2\",\n        title: \"Fifteen Years Sober — Grace Found Me in the Darkest Hour\",\n        content: `I never thought I'd be someone who shares their story publicly. I spent so many years hiding — in bottles, in excuses, in shame. But I'm fifteen years sober today, and if my words help one person hold on one more day, then every word is worth it.\\n\\nMy addiction began slowly, as they often do. A drink to relax after work. Two drinks. Then the bottle. Then anything I could get my hands on. I lost my job, my apartment, and almost my life. I sat in a hospital bed after a near-fatal incident, and a nurse — her name was Sandra — sat with me on her break and prayed over me. Just quietly, gently. She didn't ask permission. She just held my hand and spoke life over me.\\n\\nSomething changed in me that night. Not all at once — recovery isn't a light switch. But a seed was planted. I entered a faith-based recovery program and slowly, painstakingly, I began to rebuild.\\n\\nFifteen years later I am a counselor in that same program. I am a father, a husband, a man of faith. I am still standing — not by my own strength, but by grace I did nothing to deserve and everything to be grateful for.`,\n        excerpt: \"I never thought I'd be someone who shares their story publicly. I spent so many years hiding — in bottles, in excuses, in shame…\",\n        author_name: \"Marcus T.\",\n        category: \"Addiction & Recovery\",\n        image_url: null,\n        likes: 203,\n        prayers: 167,\n        encouragements: 94,\n        created_at: \"2024-11-10T14:05:00Z\",\n        is_featured: true\n    },\n    {\n        id: \"3\",\n        title: \"Diagnosed at 34 — What Chronic Illness Taught Me About Strength\",\n        content: `When the doctor said \"multiple sclerosis,\" the room seemed to tilt. I was 34, running marathons, raising two kids, building a career. I thought I was invincible.\\n\\nThe years that followed tested every belief I had. There were days I couldn't get out of bed. Days I cried in the shower so my children wouldn't hear. Days I questioned everything — my faith, my future, my purpose.\\n\\nBut in those stripped-down, raw, impossible moments, I discovered something: God meets you at your lowest. Not with easy answers or instant healing, but with a presence so steady it becomes the ground you stand on when everything else has fallen away.\\n\\nI learned to celebrate small victories. Getting dressed. Making breakfast. Walking to the mailbox. I found a community of others walking similar roads, and we became each other's strength on the days we had none of our own.\\n\\nI am still here. Still imperfect. Still in pain some days. But still standing — and standing means everything.`,\n        excerpt: \"When the doctor said 'multiple sclerosis,' the room seemed to tilt. I was 34, running marathons, raising two kids, building a career…\",\n        author_name: \"Diane K.\",\n        category: \"Health & Healing\",\n        image_url: null,\n        likes: 178,\n        prayers: 134,\n        encouragements: 72,\n        created_at: \"2024-11-05T11:30:00Z\",\n        is_featured: false\n    },\n    {\n        id: \"4\",\n        title: \"From Bankruptcy to Breakthrough — A Financial Resurrection Story\",\n        content: `Three years ago I filed for bankruptcy. I had built a business, watched it collapse, and found myself six figures in debt with a family to feed. The shame of that season nearly swallowed me whole.\\n\\nWhat I didn't expect was that hitting rock bottom would become a foundation. When there's nothing left to lose, you find out what you truly believe. For me, that was faith — raw, desperate, sincere faith that God had not abandoned me.\\n\\nI took a minimum wage job. I tithed even when it didn't make sense. I showed up every day and did the work in front of me, no matter how small it seemed.\\n\\nSlowly, things shifted. A door opened. Then another. Three years later I run a thriving small business and I teach financial literacy at my church because I know what it feels like when the numbers don't add up and hope feels foolish.\\n\\nYour story isn't over. The breakthrough is often just one faithful step ahead of where you are.`,\n        excerpt: \"Three years ago I filed for bankruptcy. I had built a business, watched it collapse, and found myself six figures in debt with a family to feed…\",\n        author_name: \"Raymond O.\",\n        category: \"Financial Breakthrough\",\n        image_url: null,\n        likes: 156,\n        prayers: 98,\n        encouragements: 88,\n        created_at: \"2024-10-28T08:15:00Z\",\n        is_featured: true\n    },\n    {\n        id: \"5\",\n        title: \"Healing the Invisible Wounds — My Journey Through Depression\",\n        content: `Depression doesn't look the way movies portray it. I was functional. I smiled at work. I showed up for my family. But inside, I was drowning in a grey ocean with no visible shore.\\n\\nFor years I thought faith meant not struggling. I was wrong. Some of the most faithful people in scripture cried out from pits of despair — David, Elijah, Jeremiah. Their honesty about suffering is in our holiest texts for a reason.\\n\\nSeeing a therapist was the bravest thing I ever did. Accepting medication was not a failure of faith — it was an act of stewardship over the mind God gave me. Slowly, with professional support and the anchor of my faith community, the grey began to lift.\\n\\nI'm not \"cured.\" I manage. I watch. I take care of myself. But I have also learned that struggle does not disqualify you from purpose. Sometimes it is the very thing that qualifies you to help others find their way through.`,\n        excerpt: \"Depression doesn't look the way movies portray it. I was functional. I smiled at work. I showed up for my family. But inside, I was drowning…\",\n        author_name: \"Priya S.\",\n        category: \"Mental Health\",\n        image_url: null,\n        likes: 231,\n        prayers: 189,\n        encouragements: 112,\n        created_at: \"2024-10-20T16:45:00Z\",\n        is_featured: false\n    },\n    {\n        id: \"6\",\n        title: \"Rebuilding After Divorce — Finding Wholeness Again\",\n        content: `My marriage ended after seventeen years. The life I had built, the identity I had formed, the future I had imagined — all of it unraveled in a matter of months. I was fifty-two years old and starting over.\\n\\nI won't pretend the process was graceful. I was angry, lost, and more lonely than I had words for. But I held onto one truth like a lifeline: I was not defined by what had broken. I was carried by what could not break.\\n\\nI began showing up to a small group at my church — reluctantly at first. But those people became my family. They fed me, prayed for me, sat with me in the hard places, and celebrated every tiny sign of forward movement.\\n\\nTwo years later, I have rebuilt a life I genuinely love. Not the life I planned — something realer, truer, more deeply mine. The breaking was real. The rebuilding is too. And God was present in every single moment of both.`,\n        excerpt: \"My marriage ended after seventeen years. The life I had built, the identity I had formed, the future I had imagined — all of it unraveled…\",\n        author_name: \"Carol J.\",\n        category: \"Family & Relationships\",\n        image_url: null,\n        likes: 119,\n        prayers: 101,\n        encouragements: 67,\n        created_at: \"2024-10-12T13:20:00Z\",\n        is_featured: false\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/lib/mockData.ts\n");

